Method.Source:
public static void main(Args args)
{
    var builder = DBMSQLDBTuningConfigurationsViewBuilder::construct();
    builder.createSqlObjects();
}

private str createViewSqlStmt()
{
    str sqlStmt = 'CREATE VIEW ' + viewName + ' AS ' + this.createSQLStatement();
    return sqlStmt;
}

protected void initialize(boolean _runOnSeparateUserConnection = false)
{
    super(_runOnSeparateUserConnection);

    SysDictView view    = new SysDictView(tableNum(DBMSQLDBTuningConfigurations));
    viewName            = view.name(DbBackend::Sql);
    asOption = view.fieldObject(fieldNum(DBMSQLDBTuningConfigurations, Option)).name(DbBackend::Sql);
    asOptionValue = view.fieldObject(fieldNum(DBMSQLDBTuningConfigurations, OptionValue)).name(DbBackend::Sql);
    asType = view.fieldObject(fieldNum(DBMSQLDBTuningConfigurations, Type)).name(DbBackend::Sql);
    asTypeValue = view.fieldObject(fieldNum(DBMSQLDBTuningConfigurations, TypeValue)).name(DbBackend::Sql);
    asDetails = view.fieldObject(fieldNum(DBMSQLDBTuningConfigurations, Details)).name(DbBackend::Sql);
    asState = view.fieldObject(fieldNum(DBMSQLDBTuningConfigurations, State)).name(DbBackend::Sql);
    asRecId = view.fieldObject(fieldNum(DBMSQLDBTuningConfigurations, RecId)).name(DbBackend::Sql);
}

public static DBMSQLDBTuningConfigurationsViewBuilder construct()
{
    return new DBMSQLDBTuningConfigurationsViewBuilder();
}
